// Recibimos el número de unidades desde el Agente
const unidades = $input.first().json.unidades || 1; 

// ACTUALIZACIÓN DE TARIFA VIGENTE ZMG 2026
const tarifaOficial = 11.00; 

const total = unidades * tarifaOficial;

return {
  costo_total: total.toFixed(2),
  moneda: "MXN",
  detalle: `Tarifa actualizada: ${unidades} unidad(es) a $11.00 c/u`
};

// ===============================
// 1. LIMPIEZA DE TEXTO
// ===============================
function limpiar(texto) {
    return texto
        .toLowerCase()
        .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
        .replace(/[^a-z0-9\s]/g, "")
        .trim();
}

// ===============================
// 2. EXTRAER CALLES (BIGRAMAS REALES)
// ===============================
function extraerCalles(texto) {
    const palabras = texto.split(" ");
    const calles = [];

    const stopWords = [
        "avenida", "calle", "av", "de", "la", "el", "y", "en",
        "parada", "ruta", "hacia", "desde", "hasta", "por",
        "autobus", "camion", "tren"
    ];

    for (let i = 0; i < palabras.length - 1; i++) {
        const p1 = palabras[i];
        const p2 = palabras[i + 1];

        if (
            p1.length > 4 &&
            p2.length > 4 &&
            !stopWords.includes(p1) &&
            !stopWords.includes(p2)
        ) {
            calles.push(p1 + " " + p2); // Ej: "lopez mateos"
        }
    }

    return calles;
}

// ===============================
// 3. DATOS DE ENTRADA
// ===============================
const steps = items[0].json.steps || [];
const rss = limpiar(items[0].json.rss_content || "");

// ===============================
// 4. CALLES DE LA RUTA
// ===============================
let callesRuta = new Set();

steps.forEach(step => {
    let texto = step.html_instructions || "";
    texto = texto.replace(/<[^>]*>?/gm, '');
    texto = limpiar(texto);

    let calles = extraerCalles(texto);
    calles.forEach(c => callesRuta.add(c));
});

// ===============================
// 5. CALLES DEL RSS
// ===============================
let callesRSS = new Set(extraerCalles(rss));

// ===============================
// 6. INTERSECCIÓN REAL
// ===============================
let coincidencias = [];

callesRuta.forEach(calle => {
    if (callesRSS.has(calle)) {
        coincidencias.push(calle.toUpperCase());
    }
});

// ===============================
// 7. CLASIFICACIÓN INTELIGENTE
// ===============================
let impacto = "NULO";
let tipoImpacto = "SIN AFECTACIÓN";
let veredicto = "";

if (coincidencias.length >= 2) {
    impacto = "ALTO";
    tipoImpacto = "AFECTA DIRECTAMENTE LA RUTA";
    veredicto = `⚠️ Impacto directo en: ${coincidencias.join(", ")}. Habrá retrasos.`;

} else if (coincidencias.length === 1) {
    impacto = "MODERADO";
    tipoImpacto = "CERCANO A LA RUTA";
    veredicto = `⚠️ Tráfico cercano en ${coincidencias[0]}. Posibles demoras.`;

} else {
    impacto = "NULO";
    tipoImpacto = "SIN AFECTACIÓN";
    veredicto = "✅ Ruta libre. Incidentes no afectan tu trayecto.";
}

// ===============================
// 8. OUTPUT FINAL
// ===============================
return [{
    impacto,
    tipoImpacto,
    coincidencias,
    totalCoincidencias: coincidencias.length,
    veredictoPersonalizado: veredicto
}];
